  return {
    status: 'Failed',
    message: 'Selected Sales Orders with Draft status cannot be converted.<br><br> If proceed, it will filter out the draft SO.'
  }
} else {
  return {
    status: 'Success',
    message: ''
  }
}

return {
  message: 'Selected Sales Order(s) already has existing Sales Invoice and cannot be converted.'
}

const soList = {{node:search_node_bOF3TVA2.data.data}}
const isMultiple = {{workflowparams:is_multiple}}
let customers = new Set(
  soList
    .map(so => so.customer_name)
);

if (customers.size > 1 && isMultiple === 'single') {
  return {
    status: 'Failed',
    code: 405,
    message: 'All selected Sales Order(s) must be from the same customer to create a single Sales Invoice.'
  }
} else {
  return {
    status: 'Success',
    code: 200,
    message: ''
  }
}

const soList = {{node:search_node_bOF3TVA2.data.data}};
const isMultiple = {{workflowparams:is_multiple}};
const convertTo = {{workflowparams:convert_to}};
const docFormat = {{node:get_node_yDMG0Sab.data.data}};
let plant_id = {{workflowparams:plant_id}} || '';
let siList = [];

if (plant_id == "" && isMultiple === "single") {
  let plants = new Set(soList.map((so) => so.plant_name));

  if (plants.size > 1) {
    plant_id = soList[0].organization_id;
  } else {
    plant_id = Array.from(plants)[0];
  }
}

const mapLineItem = (item, record, index) => {
  const lineItemPromise = {
    tax_amount: parseFloat(item.so_tax_amount).toFixed(4),
    so_order_quantity: parseFloat(item.so_quantity).toFixed(3),
    plant_id: plant_id || record.plant_name,
    si_discount: parseFloat(item.so_discount).toFixed(4),
    available_inv_qty: parseFloat(item.so_quantity).toFixed(3),
    agent_id: item.sales_person_id,
    discount_amount: parseFloat(item.so_discount_amount).toFixed(4),
    invoice_qty: parseFloat(item.so_quantity).toFixed(3),
    invoice_qty_uom_id: item.so_item_uom,
    so_order_uom_id: item.so_item_uom,
    material_desc: item.so_desc,
    more_desc: item.more_desc,
    si_discount_uom_id: item.so_discount_uom,
    item_category_id: item.item_category_id,
    payment_term_id: item.payment_term_id,
    line_so_id: record.id,
    material_name: item.item_id,
    si_amount: parseFloat(item.so_amount).toFixed(4),
    gross: parseFloat(item.so_gross).toFixed(4),
    so_line_id: item.id,
    si_tax_inclusive: item.so_tax_inclusive,
    si_tax_rate_id: item.so_tax_preference,
    tax_percent: item.so_tax_percentage,
    unit_price: item.so_item_price,
    good_delivery_quantity: 0,
    line_so_no: record.so_no,
    material_id: item.item_name,
    customer_id: item.customer_id,
    line_index: index + 1,
    area_id: item.area_id,
    line_remark_3: item.line_remark_3,
    line_remark_2: item.line_remark_2,
    line_remark_1: item.line_remark_1,
    tariff_id: item.tariff_id,
    custom_fields: item.custom_fields,
    further_description: item.further_description,
  };

  return lineItemPromise;
};

const mapHeaderData = (record, lineItemPromise, soNoDisplay, soID, totals) => {
  const data = {
    page_status: "Convert", // 'Convert' if from convert
    si_status: convertTo === "draft" ? "Draft" : "Completed",
    invoice_type: record.so_type,
    plant_id: plant_id || record.plant_name,
    so_no_display: soNoDisplay,
    gd_no_display: "",
    so_id: soID,
    gd_id: [],
    customer_id: record.customer_name,
    currency_code: record.so_currency,
    si_billing_address: record.cust_billing_address,
    si_shipping_address: record.cust_shipping_address,
    sales_invoice_no: convertTo === "draft" ? "draft" : "issued",
    sales_invoice_no_type: docFormat.id,
    sales_invoice_date: new Date().toISOString().split("T")[0],
    sales_person_id: record.so_sales_person,
    si_payment_term_id: record.so_payment_term,
    exchange_rate_currency: record.exchange_rate_currency,
    exchange_rate: record.exchange_rate,
    exchange_rate_myr: "MYR",
    si_description: "Sales",
    posted_date: "",
    si_area_id: record.so_area_id || "",
    posted_status: convertTo === "draft" ? "" : "Unposted",
    organization_id: record.organization_id,
    acc_integration_type: record.acc_integration_type,
    previous_status: "",
    customer_credit_limit: record.customer_credit_limit,
    overdue_limit: record.overdue_limit,
    outstanding_balance: record.outstanding_balance,
    overdue_inv_total_amount: record.overdue_inv_total_amount,
    is_accurate: record.is_accurate,
    is_posted: 0,
    table_si: lineItemPromise,
    total_gross_currency: record.total_gross_currency,
    total_discount_currency: record.total_discount_currency,
    total_tax_currency: record.total_tax_currency,
    total_amount_currency: record.total_amount_currency,
    total_amount_myr: "MYR",
    // Use calculated totals
    invoice_subtotal: totals.invoice_subtotal,
    invoice_total_discount: totals.invoice_total_discount,
    invoice_taxes_amount: totals.invoice_taxes_amount,
    invoice_total: totals.invoice_total,
    myr_total_amount: totals.myr_total_amount,
    tnc: record.so_tnc,
    payment_term: record.so_payment_details,
    delivery_term: record.so_delivery_term,
    remarks: record.so_remarks,
    remarks2: record.so_remarks2,
    remarks3: record.so_remarks3,
    remarks4: record.so_remarks4,
    remarks5: record.so_remarks5,
    billing_address_name: record.billing_address_name,
    billing_address_phone: record.billing_address_phone,
    billing_address_line_1: record.billing_address_line_1,
    billing_address_line_2: record.billing_address_line_2,
    billing_address_line_3: record.billing_address_line_3,
    billing_address_line_4: record.billing_address_line_4,
    billing_address_city: record.billing_address_city,
    billing_postal_code: record.billing_postal_code,
    billing_address_state: record.billing_address_state,
    billing_address_country: record.billing_address_country,
    billing_attention: record.billing_attention,
    billing_address_fax: record.billing_address_fax,
    shipping_address_name: record.shipping_address_name,
    shipping_address_phone: record.shipping_address_phone,
    shipping_address_line_1: record.shipping_address_line_1,
    shipping_address_line_2: record.shipping_address_line_2,
    shipping_address_line_3: record.shipping_address_line_3,
    shipping_address_line_4: record.shipping_address_line_4,
    shipping_address_city: record.shipping_address_city,
    shipping_postal_code: record.shipping_postal_code,
    shipping_address_state: record.shipping_address_state,
    shipping_address_country: record.shipping_address_country,
    shipping_attention: record.shipping_attention,
    shipping_address_fax: record.shipping_address_fax,
  };

  return data;
};

// Helper function to calculate totals from SO data
const calculateTotals = (soDataList) => {
  let totals = {
    invoice_subtotal: 0,
    invoice_total_discount: 0,
    invoice_taxes_amount: 0,
    invoice_total: 0,
    myr_total_amount: 0,
  };

  for (const so of soDataList) {
    totals.invoice_subtotal += parseFloat(so.so_total_gross) || 0;
    totals.invoice_total_discount += parseFloat(so.so_total_discount) || 0;
    totals.invoice_taxes_amount += parseFloat(so.so_total_tax) || 0;
    totals.invoice_total += parseFloat(so.so_total) || 0;
    totals.myr_total_amount += parseFloat(so.myr_total_amount) || 0;
  }

  // Round to 4 decimal places
  totals.invoice_subtotal = totals.invoice_subtotal.toFixed(4);
  totals.invoice_total_discount = totals.invoice_total_discount.toFixed(4);
  totals.invoice_taxes_amount = totals.invoice_taxes_amount.toFixed(4);
  totals.invoice_total = totals.invoice_total.toFixed(4);
  totals.myr_total_amount = totals.myr_total_amount.toFixed(4);

  return totals;
};

if (isMultiple === "multiple") {
  for (const soData of soList) {
    // Calculate totals for this single SO
    const totals = calculateTotals([soData]);
    let siLineItem = [];

    for (const [index, item] of soData.table_so.entries()) {
      const lineItemPromise = mapLineItem(item, soData, index);
      siLineItem.push(lineItemPromise);
    }

    const soNoDisplay = soData.so_no;
    const soID = [soData.id];
    const mappedData = mapHeaderData(
      soData,
      siLineItem,
      soNoDisplay,
      soID,
      totals,
    );
    siList.push(mappedData);
  }
} else if (isMultiple === "single") {
  const soData = soList[0];
  const soNoDisplay = soList.map((item) => item.so_no).join(", ");
  const soID = soList.map((item) => item.id);

  // Calculate totals for all SOs combined
  const totals = calculateTotals(soList);

  let siLineItem = [];
  let lineCounter = 0;
  for (const so of soList) {
    for (const item of so.table_so) {
      const lineItemPromise = mapLineItem(item, so, lineCounter);
      siLineItem.push(lineItemPromise);
      lineCounter++;
    }
  }
  const mappedData = mapHeaderData(
    soData,
    siLineItem,
    soNoDisplay,
    soID,
    totals,
  );
  siList.push(mappedData);
}

return { siList };

