const page_status = this.getValue('page_status');

if (page_status === 'View' || !value) {
    callback();
    return;
}

let organizationId = this.getVarGlobal('deptParentId');
if(organizationId === '0'){
    organizationId = this.getVarSystem('deptIds').split(',')[0];
}


db.collection("Customer")
    .where({ customer_id: value, organization_id: organizationId  })
    .get()
    .then(response => {
        const matchingCustomers = response.data || [];

        if (matchingCustomers.length === 0) {
            callback();
            return;
        }

        if (page_status === 'Edit') {
            const currentCustomerId = this.getValue('id');
            const isSameCustomer = matchingCustomers.some(customer => customer.id === currentCustomerId);
            callback(isSameCustomer ? undefined : 'Customer code already exists.');
        } else {
            callback('Customer code already exists.');
        }
    })
    .catch(error => {
        console.error("Error checking customer:", error);
        callback("Error validating customer code.");
    });

